import React, { useRef, useState, useEffect } from "react";
import { Link } from "react-router-dom"; // For navigation
import { useProducts } from '../hooks/useProducts';
import { motion } from "framer-motion";
import { useInView } from 'react-intersection-observer';

const HomePage = () => {
  const videoRef = useRef(null);
  const [isMuted, setIsMuted] = useState(true);
  const { featuredProducts, latestProducts, collections, loading } = useProducts();

  // Set up video once on mount
  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.load();
      // Attempt to play the video after loading
      const playVideo = async () => {
        try {
          await videoRef.current.play();
        } catch (err) {
          console.log("Video autoplay failed:", err);
        }
      };
      playVideo();
    }
  }, []);

  const toggleMute = (e) => {
    e?.preventDefault();
    if (videoRef.current) {
      videoRef.current.muted = !videoRef.current.muted;
      setIsMuted(videoRef.current.muted);
    }
  };

  // Hero Section
  const HeroSection = () => {
    return (
      <section
        id="navbar_hero"
        className="relative min-h-screen bg-black text-white overflow-hidden"
      >
        {/* Video Background */}
        <video
          ref={videoRef}
          autoPlay
          loop
          playsInline
          muted={isMuted}
          className="absolute top-0 left-0 w-full h-full object-cover filter brightness-50"
        >
          <source
            src="http://localhost:3000/uploads/hot-wheels.mp4"
            type="video/mp4"
          />
          Your browser does not support the video tag.
        </video>

        {/* Hero Section */}
        <div className="relative h-screen flex items-center justify-center">
          <div className="container mx-auto px-4 pt-16">
            <div className="text-center max-w-4xl mx-auto">
              <h1 className="text-4xl md:text-6xl lg:text-7xl font-bold mb-6 animate-fade-in">
                Experience Miniature
                <br />
                <span className="text-red-500">Engineering Marvel</span>
              </h1>
              <p className="text-lg md:text-xl text-gray-300 mb-8 animate-fade-in delay-200">
                Discover our exclusive collection of precision-crafted die-cast
                cars, where every detail tells a story of automotive excellence.
              </p>
              <div className="flex flex-col md:flex-row items-center justify-center gap-4 animate-fade-in delay-300">
                <Link
                  to="/collections"
                  className="px-8 py-3 bg-red-500 hover:bg-red-600 rounded-full transition-all transform hover:scale-105"
                >
                  Explore Collection
                </Link>
                <Link
                  to="/gameview"
                  className="px-8 py-3 border border-white hover:bg-white hover:text-black rounded-full transition-all transform hover:scale-105"
                >
                  View in 3D
                </Link>
              </div>
            </div>
          </div>

          {/* Decorative Elements */}
          <div className="absolute bottom-0 left-0 w-full h-32 bg-gradient-to-t from-black to-transparent"></div>
          <div className="absolute -bottom-12 left-1/2 transform -translate-x-1/2 w-full max-w-4xl">
            <div className="h-1 bg-red-500 rounded-full animate-pulse"></div>
          </div>
        </div>

        {/* Mute/Unmute Button */}
        <button
          onClick={toggleMute}
          className="absolute bottom-8 right-8 transform -translate-x-1/2 bg-black/50 hover:bg-black/80 text-white p-3 rounded-full transition-all"
        >
          <i
            className={`fa-solid ${
              isMuted ? "fa-volume-mute" : "fa-volume-up"
            } text-2xl`}
          ></i>
        </button>
      </section>
    );
  };

  // Featured Collections Section
  const CollectionsSection = () => {
    const [ref, inView] = useInView({
      triggerOnce: true,
      threshold: 0.1
    });

    return (
      <section className="py-20 bg-black">
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 20 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
          className="container mx-auto px-4"
        >
          <h2 className="text-3xl md:text-4xl font-bold mb-12 text-center text-white">
            Featured Collections
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {collections.map((collection) => (
              <motion.div
                key={collection._id}
                whileHover={{ scale: 1.05 }}
                className="relative rounded-xl overflow-hidden group"
              >
                <div className="aspect-square">
                  <img
                    src={collection.image}
                    alt={collection.name}
                    className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-110"
                  />
                </div>
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex items-end p-6">
                  <div>
                    <h3 className="text-xl font-bold text-white mb-2">{collection.name}</h3>
                    <Link
                      to={`/collections/${collection._id}`}
                      className="text-red-500 hover:text-red-400 transition-colors"
                    >
                      Explore Collection →
                    </Link>
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </section>
    );
  };

  // Latest Products Section
  const LatestProductsSection = () => {
    const [ref, inView] = useInView({
      triggerOnce: true,
      threshold: 0.1
    });

    return (
      <section className="py-20 bg-black">
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 20 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
          className="container mx-auto px-4"
        >
          <h2 className="text-3xl md:text-4xl font-bold mb-12 text-center text-white">
            Latest Arrivals
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {latestProducts.map((product, index) => (
              <motion.div
                key={product._id}
                initial={{ opacity: 0, y: 20 }}
                animate={inView ? { opacity: 1, y: 0 } : {}}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                whileHover={{ y: -10 }}
                className="bg-zinc-900 rounded-xl overflow-hidden"
              >
                <div className="aspect-square">
                  <img
                    src={product.image}
                    alt={product.name}
                    className="w-full h-full object-cover"
                  />
                </div>
                <div className="p-6">
                  <h3 className="text-lg font-bold text-white mb-2">{product.name}</h3>
                  <p className="text-gray-400 mb-4">{product.description}</p>
                  <div className="flex items-center justify-between">
                    <span className="text-red-500 font-bold">${product.price}</span>
                    <Link
                      to={`/products/${product._id}`}
                      className="px-4 py-2 bg-red-500 hover:bg-red-600 rounded-full text-sm transition-colors"
                    >
                      View Details
                    </Link>
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </section>
    );
  };

  return (
    <div id="root" className="pt-16">
      <HeroSection />
      <CollectionsSection />
      <LatestProductsSection />

      <style>
        {`
          @keyframes fadeIn {
            from {
              opacity: 0;
              transform: translateY(20px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }

          .animate-fade-in {
            animation: fadeIn 0.8s ease-out forwards;
          }

          .delay-200 {
            animation-delay: 200ms;
          }

          .delay-300 {
            animation-delay: 300ms;
          }


        `}
      </style>

      <script
        type="module"
        src="https://unpkg.com/@google/model-viewer/dist/model-viewer.min.js"
      ></script>
    </div>
  );
};

export default HomePage;
